mapper.select:
SELECT tr.*
FROM task_recipients tr
INNER JOIN internal_tasks it ON tr.task_id = it.id
WHERE tr.user_id = #{userId}
  AND tr.inbox_type = #{inboxType}
ORDER BY it.created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM task_recipients tr
INNER JOIN internal_tasks it ON tr.task_id = it.id
WHERE tr.user_id = #{userId}
  AND tr.inbox_type = #{inboxType}

mapper.update:
UPDATE task_recipients
SET inbox_type = #{newType}
WHERE task_id = #{taskId}
  AND user_id = #{userId}
  AND inbox_type = #{oldType}

UPDATE task_recipients
SET read_at = NOW()
WHERE id = #{id}
